// Wails v2 runtime compatibility layer, generated by `wails3 migrate`.
// It implements the classic wailsjs/runtime API on top of @wailsio/runtime
// (the Wails v3 runtime). New code should import '@wailsio/runtime' directly.

import {Application, Browser, Clipboard, Events, Screens, System, Window} from '@wailsio/runtime';

function unpack(callback) {
    return (ev) => {
        const data = ev ? ev.data : undefined;
        if (data === null || data === undefined) {
            callback();
        } else if (Array.isArray(data)) {
            callback(...data);
        } else {
            callback(data);
        }
    };
}

/* ------------------------------- Events -------------------------------- */

export function EventsOn(eventName, callback) {
    return Events.On(eventName, unpack(callback));
}

export function EventsOnMultiple(eventName, callback, maxCallbacks) {
    return Events.OnMultiple(eventName, unpack(callback), maxCallbacks);
}

export function EventsOnce(eventName, callback) {
    return Events.Once(eventName, unpack(callback));
}

export function EventsOff(eventName, ...additionalEventNames) {
    Events.Off(eventName, ...additionalEventNames);
}

export function EventsOffAll() {
    Events.OffAll();
}

export function EventsEmit(eventName, ...args) {
    const data = args.length === 0 ? null : (args.length === 1 ? args[0] : args);
    void Events.Emit(eventName, data);
}

/* -------------------------------- Logs --------------------------------- */
// v2 forwarded these to the application logger; the v3 bridge logs to the
// browser console instead. Use structured logging in Go for application logs.

export function LogPrint(message) { console.log(message); }
export function LogTrace(message) { console.debug(message); }
export function LogDebug(message) { console.debug(message); }
export function LogInfo(message) { console.info(message); }
export function LogWarning(message) { console.warn(message); }
export function LogError(message) { console.error(message); }
export function LogFatal(message) { console.error(message); }

/* ------------------------------- Window -------------------------------- */

export function WindowReload() { void Window.Reload(); }
export function WindowReloadApp() { void Window.ForceReload(); }
export function WindowSetAlwaysOnTop(b) { void Window.SetAlwaysOnTop(b); }

export function WindowSetSystemDefaultTheme() {
    console.warn('WindowSetSystemDefaultTheme: not supported by the Wails v3 compatibility layer; the theme is set at window creation.');
}
export function WindowSetLightTheme() {
    console.warn('WindowSetLightTheme: not supported by the Wails v3 compatibility layer; the theme is set at window creation.');
}
export function WindowSetDarkTheme() {
    console.warn('WindowSetDarkTheme: not supported by the Wails v3 compatibility layer; the theme is set at window creation.');
}

export function WindowCenter() { void Window.Center(); }
export function WindowSetTitle(title) { void Window.SetTitle(title); }
export function WindowFullscreen() { void Window.Fullscreen(); }
export function WindowUnfullscreen() { void Window.UnFullscreen(); }
export function WindowIsFullscreen() { return Window.IsFullscreen(); }
export function WindowSetSize(width, height) { void Window.SetSize(width, height); }

export function WindowGetSize() {
    return Window.Size().then((s) => ({w: s.width ?? s.Width ?? 0, h: s.height ?? s.Height ?? 0}));
}

export function WindowSetMaxSize(width, height) { void Window.SetMaxSize(width, height); }
export function WindowSetMinSize(width, height) { void Window.SetMinSize(width, height); }

// v2 positions were relative to the current screen.
export function WindowSetPosition(x, y) { void Window.SetRelativePosition(x, y); }
export function WindowGetPosition() {
    return Window.RelativePosition().then((p) => ({x: p.x ?? p.X ?? 0, y: p.y ?? p.Y ?? 0}));
}

export function WindowHide() { void Window.Hide(); }
export function WindowShow() { void Window.Show(); }
export function WindowMaximise() { void Window.Maximise(); }
export function WindowToggleMaximise() { void Window.ToggleMaximise(); }
export function WindowUnmaximise() { void Window.UnMaximise(); }
export function WindowIsMaximised() { return Window.IsMaximised(); }
export function WindowMinimise() { void Window.Minimise(); }
export function WindowUnminimise() { void Window.UnMinimise(); }
export function WindowIsMinimised() { return Window.IsMinimised(); }

export function WindowIsNormal() {
    return Promise.all([Window.IsFullscreen(), Window.IsMaximised(), Window.IsMinimised()])
        .then(([f, max, min]) => !f && !max && !min);
}

export function WindowSetBackgroundColour(R, G, B, A) {
    void Window.SetBackgroundColour(R, G, B, A);
}

export function WindowPrint() { void Window.Print(); }

/* ------------------------------- Screens ------------------------------- */

export function ScreenGetAll() {
    return Promise.all([Screens.GetAll(), Screens.GetCurrent().catch(() => null)])
        .then(([screens, current]) => screens.map((s) => {
            const size = {
                width: (s.Size && (s.Size.width ?? s.Size.Width)) ?? 0,
                height: (s.Size && (s.Size.height ?? s.Size.Height)) ?? 0,
            };
            const phys = s.PhysicalBounds || {};
            return {
                isCurrent: !!current && s.ID === current.ID,
                isPrimary: !!s.IsPrimary,
                width: size.width,
                height: size.height,
                size: size,
                physicalSize: {
                    width: phys.Width ?? phys.width ?? size.width,
                    height: phys.Height ?? phys.height ?? size.height,
                },
            };
        }));
}

/* ----------------------------- Application ----------------------------- */

export function BrowserOpenURL(url) { void Browser.OpenURL(url); }

export function Environment() {
    return System.Environment().then((env) => ({
        buildType: env.Debug ? 'dev' : 'production',
        platform: (env.OS || '').toLowerCase(),
        arch: env.Arch,
    }));
}

export function Quit() { void Application.Quit(); }
export function Hide() { void Application.Hide(); }
export function Show() { void Application.Show(); }

/* ------------------------------ Clipboard ------------------------------ */

export function ClipboardGetText() { return Clipboard.Text(); }
export function ClipboardSetText(text) { return Clipboard.SetText(text).then(() => true); }

/* ------------------------------ File drop ------------------------------ */

export function OnFileDrop(callback, useDropTarget) {
    console.warn('OnFileDrop: not supported by the Wails v3 compatibility layer; use the v3 file drop events instead.');
}

export function OnFileDropOff() {
    console.warn('OnFileDropOff: not supported by the Wails v3 compatibility layer.');
}
